426	/// Restore `repo` to the operation identified by `op_id`.
427	///
428	/// Thin wrapper around `jj op restore`. Called during the failure
429	/// revert path — drops the caller's returned stdout. Exposed at
430	/// `pub(crate)` so `push` reuses the same restore call.
431	pub(crate) fn op_restore(repo: &Path, op_id: &str) -> Result<(), Box<dyn std::error::Error>> {
432	    run(
433	        "jj",
434	        &["op", "restore", op_id, "-R", &repo_str(repo)],
435	        Path::new("."),
436	    )?;
437	    Ok(())
438	}
