221	/// diagnostic; promoted to permanent in 0.37.4 after the user
222	/// reported "happens more than once" — the signal is worth keeping
223	/// in place until confidence in its correctness is well-established
224	/// across varied use, at which point a "silent when clean"
225	/// refinement would remove the steady-state noise without losing
226	/// detection value (see `notes/todo.md`).
227	///
228	/// Walks up from cwd to locate the workspace root (the directory
229	/// whose `.vc-config.toml` has `path = "/"`), then probes `<root>`
230	/// and `<root>/.claude`. Same labeling whether the user runs from
231	/// the app root, from `.claude`, or from any subdir.
232	fn bm_track(phase: &str, command_name: &str) {
233	    let header = format!("bm-track {phase} vc-x1 {command_name}");
234	    let root = match find_workspace_root() {
235	        Some(r) => r,
236	        None => {
237	            log::info!("{header}: no-workspace");
238	            return;
239	        }
240	    };
241	    let repos: [(std::path::PathBuf, &str); 2] =
242	        [(root.clone(), "app"), (root.join(".claude"), ".claude")];
243	    let mut parts: Vec<String> = Vec::new();
244	    for (repo, label) in repos {
245	        if !repo.join(".jj").exists() {
246	            parts.push(format!("{label}(main)=no-jj"));
247	            continue;
248	        }
249	        match bm_track_one(&repo, "main", "origin") {
250	            Ok(true) => parts.push(format!("{label}(main)=tracked")),
251	            Ok(false) => parts.push(format!("{label}(main)=NOT_TRACKED")),
252	            Err(e) => parts.push(format!(
