    pub bookmark: String,

    /// Remote to sync against
    #[arg(long, default_value = "origin")]
    pub remote: String,

    /// Path to jj repo; repeatable or comma-separated [default: `.,.claude`]
    #[arg(short = 'R', long = "repo", value_name = "PATH")]
    pub repos: Vec<PathBuf>,
}

