    /// repo set is derived from `--scope` defaults.
    #[arg(short = 'R', long = "repo", value_name = "PATH", conflicts_with = "scope")]
    pub repos: Vec<PathBuf>,

    /// Which side(s) of the workspace to sync.
    ///
    /// `SCOPE=code|bot|code,bot`:
    ///
    /// - `code` — single-repo operation on the app repo.
    /// - `bot` — single-repo operation on the bot repo (errors if the
    ///   workspace doesn't define one).
    /// - `code,bot` — dual-repo (default in a dual-repo workspace).
    #[arg(
        long,
        value_name = "SCOPE",
        value_delimiter = ',',
        verbatim_doc_comment
    )]
    pub scope: Option<Vec<Side>>,
}

