164	/// Run a shell command. Returns stdout on success.
165	///
166	/// Logs the command at `debug!` and the process streams as follows:
167	/// - **stderr at `debug!`** on success — jj's chatter (`Moved 1 bookmarks
168	///   to …`, `Rebased N commits`, `Nothing changed.`) is hidden by default
169	///   and surfaced with `-v`. The debug formatter indents each line two
170	///   spaces so subprocess output sits visually under the caller's own
171	///   `info!` line in `-v` mode.
172	/// - **stdout at `debug!`** — callers usually consume stdout as data
173	///   (bookmark lists, commit IDs, etc.), and `info!` would flood the user
174	///   with machine-readable output they didn't ask for.
175	/// - **Failures propagate as `Err`** carrying the stderr; the caller's
176	///   error handler (`main::run_command`) surfaces it at `error!`.
177	pub fn run(cmd: &str, args: &[&str], cwd: &Path) -> Result<String, Box<dyn std::error::Error>> {
178	    let args_str = args.join(" ");
179	    debug!("$ {cmd} {args_str}");
180	    trace!("cwd: {}", cwd.display());
181	    let output = std::process::Command::new(cmd)
182	        .args(args)
183	        .current_dir(cwd)
184	        .output()
185	        .map_err(|e| format!("failed to run {cmd}: {e}"))?;
186	    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
187	    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
188	    if !stdout.is_empty() {
189	        debug!("{stdout}");
190	    }
191	    if !output.status.success() {
192	        return Err(format!("{cmd} {args_str} failed: {stderr}").into());
193	    }
194	    if !stderr.is_empty() {
195	        debug!("{stderr}");
196	    }
197	    Ok(stdout)
198	}
